const response = $input.first().json;
const body = response.body || response;

// SmartCity API returns entities array
const entities = Array.isArray(body) ? body : (body.entities || body.data || []);

const rows = [];
const now = new Date().toISOString();

for (const entity of entities) {
  const sensorId = entity.id || entity.entityId || 'unknown';
  const timestamp = entity.timestamp || entity.dateObserved || now;

  // Extract vehicle counts from entity attributes
  const vehicleTypes = {
    car: entity.car || entity.carCount || 0,
    truck: entity.truck || entity.truckCount || 0,
    motorbike: entity.motorbike || entity.motorbikeCount || 0,
    bicycle: entity.bicycle || entity.bicycleCount || 0,
    pedestrian: entity.pedestrian || entity.pedestrianCount || 0
  };

  // Also check for lane-based data structure
  if (entity.lanes) {
    for (const lane of entity.lanes) {
      if (lane.classes) {
        for (const cls of lane.classes) {
          const vType = cls.class || cls.type || 'unknown';
          const count = cls.count || 0;
          if (count > 0) {
            rows.push({ sensor_id: sensorId, timestamp, vehicle_type: vType, count });
          }
        }
      }
    }
  }

  // Add flat vehicle counts
  for (const [vType, count] of Object.entries(vehicleTypes)) {
    if (count > 0) {
      rows.push({ sensor_id: sensorId, timestamp, vehicle_type: vType, count });
    }
  }
}

if (rows.length === 0) {
  rows.push({ sensor_id: 'none', timestamp: now, vehicle_type: 'none', count: 0, _empty: true });
}

return rows.filter(r => !r._empty).map(r => ({ json: r }));

const input = $input.first().json;
const errorMsg = input.error || input.message || 'API request failed';
const statusCode = input.statusCode || 'unknown';

console.log(`SmartCity API error: status=${statusCode}, message=${errorMsg}`);

return [{ json: { error: true, statusCode, message: errorMsg, timestamp: new Date().toISOString() } }];
